(48,'Newsletter Subscription','dockercart_newsletter','{\"name\":\"Newsletter Subscription\",\"status\":\"1\",\"title\":{\"1\":\"Stay in the Loop\",\"2\":\"\\u0411\\u0443\\u0434\\u044c\\u0442\\u0435 \\u0432 \\u043a\\u0443\\u0440\\u0441\\u0456\"},\"subtitle\":{\"1\":\"Get the latest deals, new arrivals and exclusive offers straight to your inbox.\",\"2\":\"\\u041e\\u0442\\u0440\\u0438\\u043c\\u0443\\u0439\\u0442\\u0435 \\u043e\\u0441\\u0442\\u0430\\u043d\\u043d\\u0456 \\u043f\\u0440\\u043e\\u043f\\u043e\\u0437\\u0438\\u0446\\u0456\\u0457, \\u043d\\u043e\\u0432\\u0456 \\u043d\\u0430\\u0434\\u0445\\u043e\\u0434\\u0436\\u0435\\u043d\\u043d\\u044f \\u0442\\u0430 \\u0435\\u043a\\u0441\\u043a\\u043b\\u044e\\u0437\\u0438\\u0432\\u043d\\u0456 \\u043f\\u0440\\u043e\\u043f\\u043e\\u0437\\u0438\\u0446\\u0456\\u0457 \\u043f\\u0440\\u044f\\u043c\\u043e \\u0443 \\u0441\\u0432\\u043e\\u044e \\u043f\\u043e\\u0448\\u0442\\u043e\\u0432\\u0443 \\u0441\\u043a\\u0440\\u0438\\u043d\\u044c\\u043a\\u0443.\"},\"placeholder\":{\"1\":\"Enter your email address\",\"2\":\"\\u0412\\u0432\\u0435\\u0434\\u0456\\u0442\\u044c \\u0441\\u0432\\u043e\\u044e \\u0430\\u0434\\u0440\\u0435\\u0441\\u0443 \\u0435\\u043b\\u0435\\u043a\\u0442\\u0440\\u043e\\u043d\\u043d\\u043e\\u0457 \\u043f\\u043e\\u0448\\u0442\\u0438\"},\"button_text\":{\"1\":\"Subscribe\",\"2\":\"\\u041f\\u0456\\u0434\\u043f\\u0438\\u0441\\u0430\\u0442\\u0438\\u0441\\u044f\"},\"privacy_text\":{\"1\":\"By subscribing you agree to our Privacy Policy.\",\"2\":\"\\u041f\\u0456\\u0434\\u043f\\u0438\\u0441\\u0443\\u044e\\u0447\\u0438\\u0441\\u044c, \\u0432\\u0438 \\u043f\\u043e\\u0433\\u043e\\u0434\\u0436\\u0443\\u0454\\u0442\\u0435\\u0441\\u044f \\u0437 \\u043d\\u0430\\u0448\\u043e\\u044e \\u041f\\u043e\\u043b\\u0456\\u0442\\u0438\\u043a\\u043e\\u044e \\u043a\\u043e\\u043d\\u0444\\u0456\\u0434\\u0435\\u043d\\u0446\\u0456\\u0439\\u043d\\u043e\\u0441\\u0442\\u0456.\"},\"success_text\":{\"1\":\"Thanks! You are now subscribed.\",\"2\":\"\\u0414\\u044f\\u043a\\u0443\\u0454\\u043c\\u043e! \\u0412\\u0438 \\u0442\\u0435\\u043f\\u0435\\u0440 \\u043f\\u0456\\u0434\\u043f\\u0438\\u0441\\u0430\\u043d\\u0456.\"},\"already_text\":{\"1\":\"You are subscribed\",\"2\":\"\\u0412\\u0438 \\u043f\\u0456\\u0434\\u043f\\u0438\\u0441\\u0430\\u043d\\u0456\"}}'),
(49,'Home Features','banner','{\"name\":\"Home Features\",\"banner_id\":\"9\",\"width\":\"390\",\"height\":\"260\",\"status\":\"1\"}'),
(50,'Store Features','dockercart_shop_features','{\"name\":\"Store Features\",\"status\":\"1\",\"features\":[{\"icon\":\"truck\",\"sort_order\":0,\"title\":{\"1\":\"Free Shipping\",\"2\":\"\\u0411\\u0435\\u0437\\u043a\\u043e\\u0448\\u0442\\u043e\\u0432\\u043d\\u0430 \\u0434\\u043e\\u0441\\u0442\\u0430\\u0432\\u043a\\u0430\"},\"text\":{\"1\":\"On all orders over $49. Worldwide delivery available.\",\"2\":\"\\u0414\\u043b\\u044f \\u0432\\u0441\\u0456\\u0445 \\u0437\\u0430\\u043c\\u043e\\u0432\\u043b\\u0435\\u043d\\u044c \\u043f\\u043e\\u043d\\u0430\\u0434 49 \\u0434\\u043e\\u043b\\u0430\\u0440\\u0456\\u0432. \\u0414\\u043e\\u0441\\u0442\\u0443\\u043f\\u043d\\u0430 \\u0434\\u043e\\u0441\\u0442\\u0430\\u0432\\u043a\\u0430 \\u043f\\u043e \\u0432\\u0441\\u044c\\u043e\\u043c\\u0443 \\u0441\\u0432\\u0456\\u0442\\u0443.\"}},{\"icon\":\"shield-check\",\"sort_order\":1,\"title\":{\"1\":\"2-Year Warranty\",\"2\":\"2-\\u0440\\u0456\\u0447\\u043d\\u0430 \\u0433\\u0430\\u0440\\u0430\\u043d\\u0442\\u0456\\u044f\"},\"text\":{\"1\":\"All products covered. No questions asked repairs.\",\"2\":\"\\u0412\\u0441\\u044f \\u043f\\u0440\\u043e\\u0434\\u0443\\u043a\\u0446\\u0456\\u044f \\u043f\\u043e\\u043a\\u0440\\u0438\\u0432\\u0430\\u0454\\u0442\\u044c\\u0441\\u044f. \\u0420\\u0435\\u043c\\u043e\\u043d\\u0442 \\u0431\\u0435\\u0437 \\u0437\\u0430\\u0439\\u0432\\u0438\\u0445 \\u043f\\u0438\\u0442\\u0430\\u043d\\u044c.\"}},{\"icon\":\"refresh-ccw\",\"sort_order\":2,\"title\":{\"1\":\"Easy Returns\",\"2\":\"2-\\u0440\\u0456\\u0447\\u043d\\u0430 \\u0433\\u0430\\u0440\\u0430\\u043d\\u0442\\u0456\\u044f\"},\"text\":{\"1\":\"30-day hassle-free returns on all items.\",\"2\":\"\\u0412\\u0441\\u044f \\u043f\\u0440\\u043e\\u0434\\u0443\\u043a\\u0446\\u0456\\u044f \\u043f\\u043e\\u043a\\u0440\\u0438\\u0432\\u0430\\u0454\\u0442\\u044c\\u0441\\u044f. \\u0420\\u0435\\u043c\\u043e\\u043d\\u0442 \\u0431\\u0435\\u0437 \\u0437\\u0430\\u0439\\u0432\\u0438\\u0445 \\u043f\\u0438\\u0442\\u0430\\u043d\\u044c.\"}},{\"icon\":\"headset\",\"sort_order\":3,\"title\":{\"1\":\"24\\/7 Support\",\"2\":\"\\u041f\\u0456\\u0434\\u0442\\u0440\\u0438\\u043c\\u043a\\u0430 24\\/7\"},\"text\":{\"1\":\"Live chat, email, and phone support any time.\",\"2\":\"\\u041f\\u0456\\u0434\\u0442\\u0440\\u0438\\u043c\\u043a\\u0430 \\u0432 \\u0447\\u0430\\u0442\\u0456, \\u0435\\u043b\\u0435\\u043a\\u0442\\u0440\\u043e\\u043d\\u043d\\u043e\\u044e \\u043f\\u043e\\u0448\\u0442\\u043e\\u044e \\u0442\\u0430 \\u0442\\u0435\\u043b\\u0435\\u0444\\u043e\\u043d\\u043e\\u043c \\u0443 \\u0431\\u0443\\u0434\\u044c-\\u044f\\u043a\\u0438\\u0439 \\u0447\\u0430\\u0441.\"}}]}');
